fun solve(nums: Array<Long>): Long {
    fun isPrime(n: Long): Boolean {
        return if (n <= 1) false else if (n == 2) true else if (n % 2 == 0) false else
            (3..Math.sqrt(n.toDouble())).all { i -> n % i != 0 }
    }

    var sumA = 0L
    var sumB = 0L

    for (i in nums.indices) {
        if (isPrime(i.toLong())) {
            sumA += nums[i]
        } else {
            sumB += nums[i]
        }
    }

    return (sumA - sumB).abs
}
